values ('br-ernanileiloeiro-com-br-29423251', 'br-ernanileiloeiro-com-br-29423251', '2026-w25-todos', 'Limoges: Pequenino prato, decorativo, em porcelana francesa. Ao centro, imagem do Príncipe Rainier III e da Princesa Grace Kelly de Mônaco, coroa no alto, bordas onduladas. souvenir casa da real de Mônaco. Realces em dourado. No verso, carimbo, em dourado, da manufatura e estrutura em metal. Medida: 9cm de diâmetro.', 72.0, 'lance r$ 72', 'Ernani Leiloeiro Oficial', 'https://br.ernanileiloeiro.com.br/peca.asp?Id=29423251', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/56361/29423251.jpg', '2026-06-23 15:00:00', 29.2, 'baixa', 'medio', null, 12, 'queued', '{"uf": "RJ", "house_name": "Ernani Leiloeiro Oficial", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "pequeno", "price_sale": 227, "price_band": "até R$ 400", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de marca"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
