values ('br-ernanileiloeiro-com-br-29409195', 'br-ernanileiloeiro-com-br-29409195', '2026-w25-todos', '''Vista Alegre''. Porcelana branca: dois bowls (13,5x4cm.) e três pequenos medalhões (14x1,5cm). Duas paisagens campestres diversas em ocre, com cena romântica e/ou carroça. Bordas decoradas com ocre e dourado. Marca da porcelana nas bases em verde e ''A ok'' in cavun nos pratinhos. Sinais de uso.', 12.0, 'lance r$ 12', 'Ernani Leiloeiro Oficial', 'https://br.ernanileiloeiro.com.br/peca.asp?Id=29409195', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/56361/29409195.jpg', '2026-06-23 15:00:00', 29.2, 'baixa', 'medio', null, 2, 'queued', '{"uf": "RJ", "house_name": "Ernani Leiloeiro Oficial", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "pequeno", "price_sale": 227, "price_band": "até R$ 400", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de marca"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
