values ('wattenleiloes-com-br-31024859', 'wattenleiloes-com-br-31024859', '2026-w25-todos', 'LINDÍSSIMO LUSTRE ESTILO OVERLAY EM OPALINA BRANCA, RICAMENTE DECORADO COM SOBREPOSIÇÕES EM TOM RUBI, DETALHES FLORAIS DOURADOS PINTADOS À MÃO E APLICAÇÕES ORNAMENTAIS, COMPOSTO POR QUATRO BRAÇOS CURVOS PARA ILUMINAÇÃO, BOBÈCHES RECORTADAS E PINGENTES EM CRISTAL LAPIDADO FACETADO. APRESENTA HASTE CENTRAL ELEGANTEMENTE TRABALHADA E FINALIZAÇÃO INFERIOR COM PRISMA ESFÉRICO. LUSTRE EM PERFEITO ESTADO. FIAÇÃO NÃO TESTADA. EUROPA SÉC XIX / XX  MEDIDA 70 X 50 CM. *ESTE LOTE NÃO PODERÁ SER ENVIADO PELOS CORREIOS. TRANSPORTADORA INDICADA PELO CLIENTE.*', 2500.0, 'lance r$ 2.500', 'Watten Leilões', 'https://wattenleiloes.com.br/peca.asp?Id=31024859', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62002/31024859.jpg', null, 27.5, 'baixa', 'medio', null, 1, 'queued', '{"uf": null, "house_name": "Watten Leilões", "item_type": "luminaria_lustre", "material": "cristal & vidro", "size_label": "grande", "price_sale": 4500, "price_band": "R$ 2.500 +", "era": null, "est_resale_base": 360, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["cristal & vidro", "peça de marca"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
