values ('danielbastosleiloeiro-com-br-31011753', 'danielbastosleiloeiro-com-br-31011753', '2026-w25-todos', 'Linda tapeçaria  paisagem tropical ao entardecer, com silhueta de coqueiros refletidos sobre o espelho dágua e céu em tons quentes de laranja, vermelho e amarelo contrastando com sombras em preto e verde-azulado, escola Bahiana, moldura em madeira escura, medindo 67x92cm e tapeçaria 55x79cm', 70.0, 'lance r$ 70', 'Daniel Bastos Leiloeiro Público', 'https://danielbastosleiloeiro.com.br/peca.asp?Id=31011753', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62124/31011753.jpg', '2026-06-15 19:00:00', 18.0, 'baixa', 'medio', null, 3, 'queued', '{"uf": "RJ", "house_name": "Daniel Bastos Leiloeiro Público", "item_type": "espelho", "material": "espelho", "size_label": "grande", "price_sale": 1134, "price_band": "R$ 800 – 1.500", "era": null, "est_resale_base": 630, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["espelho", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
