values ('artemaiorleiloes-com-br-31141006', 'artemaiorleiloes-com-br-31141006', '2026-w25-todos', 'Maria Carmen - 1935/2014 - Quadro óleo sobre eucatex, medindo 49x73cm, com moldura, ano 1988. Maria Carmen de Queirós Bastos, foi uma artista plástica pernambucana, nasceu em Recife em 1935. Ela foi pintora, desenhista e escultora, tendo estudado escultura no Rio de Janeiro e desenho com grandes mestres em Pernambuco, como Abelardo da Hora, faleceu em 2014.', 2000.0, 'lance r$ 2.000', 'Arte Maior Leilões', 'https://artemaiorleiloes.com.br/peca.asp?Id=31141006', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62371/31141006.jpg', '2026-06-16 19:00:00', 17.8, 'baixa', 'medio', null, 0, 'queued', '{"uf": "PE", "house_name": "Arte Maior Leilões", "item_type": "escultura", "material": "escultura", "size_label": "grande", "price_sale": 3600, "price_band": "R$ 2.500 +", "era": null, "est_resale_base": 288, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["escultura", "peça de catálogo"], "risk_reasons": ["liquidez baixa"]}'::jsonb, '2026-06-16T04:19:38Z')
