values ('garimpoleiloes-com-br-30952411', 'garimpoleiloes-com-br-30952411', '2026-w25-todos', 'Carmem Flora  (Nascida no RS, radicada no RJ, escultora e pintora, recebeu inúmeros prêmios: Medalha de Ouro (escultura) - Academia de Belas Artes, Menção honrosa (pintura) XXVI Salão de Belas Artes do Clube Naval, Medalha de Bronze (pintura) Sociedade Brasileira de Belas Artes, Medalha de Ouro (pintura) - XIV Salão de Itatiaia-  Quadro Óleo s/tela, de figura masculina com realismo contemporâneo, focando na forma humana e na expressão emocional.  78,5 x 64 cm s/moldura e 104 x 90 cm c/moldura', 1500.0, 'lance r$ 1.500', 'Garimpo Leilões', 'https://garimpoleiloes.com.br/peca.asp?Id=30952411', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62132/30952411.jpg', '2026-06-16 19:00:00', 17.8, 'baixa', 'medio', null, 0, 'queued', '{"uf": "RS", "house_name": "Garimpo Leilões", "item_type": "escultura", "material": "bronze", "size_label": "grande", "price_sale": 2700, "price_band": "R$ 2.500 +", "era": null, "est_resale_base": 288, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["bronze", "peça de catálogo"], "risk_reasons": ["liquidez baixa"]}'::jsonb, '2026-06-16T04:19:38Z')
