values ('vmescritarteleiloes-com-br-31077586', 'vmescritarteleiloes-com-br-31077586', '2026-w25-todos', 'Urna, com tampa, de prata de lei brasileira, contraste "MFS Coroa", teor de toque 0,925, lavrada ao estilo das antigas peças alemãs de Hanau, composta de base circular ornada com acantos, sustentada por tripé em garras com ornatos, encimada por fuste central em figurações mitológicas de querubins, copo em fino trabalho de cinzelamentos e repuxes com barrado de desenhos de folhas e penachos estilizados, arrematado na parte superior por cercadura de motivos florais e tampa decorada "en suite" com pega em pequena escultura de pássaro sobre pétala invertida. 10,5 cm de diâmetro e 26 cm de altura. Peso de 355 g. Brasil, década de 1940.', 2600.0, 'lance r$ 2.600', 'VM Escritório de Arte', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31077586', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31077586.jpg', '2026-06-17 20:00:00', 17.8, 'baixa', 'medio', null, 1, 'queued', '{"uf": "SP", "house_name": "VM Escritório de Arte", "item_type": "escultura", "material": "prata & metal", "size_label": "médio", "price_sale": 4680, "price_band": "R$ 2.500 +", "era": null, "est_resale_base": 288, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["prata & metal", "peça de catálogo"], "risk_reasons": ["liquidez baixa"]}'::jsonb, '2026-06-16T04:19:38Z')
