values ('velhooesteantiguidades-com-br-31039147', 'velhooesteantiguidades-com-br-31039147', '2026-w25-todos', 'França - Raro Sifão / Garrafa de Água de Seltz Francesa (Século XIX)  Hérault Paris Peça histórica legítima da segunda metade do século XIX (circa 1860/1880), fabricada na França. Este aparelho de porcelana pesada possui o clássico sistema de dois compartimentos internos independentes, utilizado na época para gerar água gaseificada de forma doméstica através de reação química. Autenticidade: Carimbo original na base intacto: " Appareil à Eau de Seltz - Déposé - Herault Paris" Material: Porcelana branca espessa de alta qualidade com detalhes esculpidos em relevo.21 cm de altura e 19 cm da alça ao bico.', 65.0, 'lance r$ 65', 'Velho Oeste Antiguidades', 'https://velhooesteantiguidades.com.br/peca.asp?Id=31039147', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62312/31039147.jpg', '2026-06-15 19:00:00', 14.5, 'baixa', 'medio', null, 1, 'queued', '{"uf": "SC", "house_name": "Velho Oeste Antiguidades", "item_type": "luminaria_lustre", "material": "porcelana & cerâmica", "size_label": "pequeno", "price_sale": 648, "price_band": "R$ 400 – 800", "era": null, "est_resale_base": 360, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
