values ('marirodriguesleiloeira-com-br-31119940', 'marirodriguesleiloeira-com-br-31119940', '2026-w25-todos', 'A. MARIONNET / A. INROFILAC - Caixa porta-joias Art Nouveau em bronze dourado, ricamente trabalhada no estilo, com decoração em relevo de folhagens, ramos e flores estilizadas, apresentando tampa abaulada ornada por rosas e laterais com motivos orgânicos sinuosos. Interior revestido, assente sobre pés recortados, cerca 1900. Medidas: 10 cm (A) x 22 cm (L) x 14 cm (P).', 421.0, 'lance r$ 421', 'Marilaine Rodrigues - Leiloeira Pública', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31119940', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31119940.jpg', '2026-06-15 15:00:00', 14.1, 'baixa', 'medio', null, 9, 'queued', '{"uf": "RJ", "house_name": "Marilaine Rodrigues - Leiloeira Pública", "item_type": "prata_metal", "material": "bronze", "size_label": "pequeno", "price_sale": 758, "price_band": "R$ 400 – 800", "era": "art nouveau", "est_resale_base": 216, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["bronze", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
