values ('marirodriguesleiloeira-com-br-31120366', 'marirodriguesleiloeira-com-br-31120366', '2026-w25-todos', 'Açucareiro com a respectiva concha em prata inglesa contrastada, teor 925 mls. apresentando elegante desenho de inspiração neoclássica, corpo de linhas fluidas e bojo elevado sobre base circular escalonada. A pega superior em voluta estilizada confere refinamento escultórico à peça. Acompanha concha original também em prata inglesa, de cabo torneado. Contrastes ingleses visíveis no corpo e na concha. Inglaterra, século XX. Medidas: 15 cm x 9 cm. Peso total 247 gramas.', 1600.0, 'lance r$ 1.600', 'Marilaine Rodrigues - Leiloeira Pública', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31120366', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31120366.jpg', '2026-06-15 15:00:00', 14.1, 'baixa', 'medio', null, 1, 'queued', '{"uf": "RJ", "house_name": "Marilaine Rodrigues - Leiloeira Pública", "item_type": "prata_metal", "material": "prata & metal", "size_label": "pequeno", "price_sale": 2880, "price_band": "R$ 2.500 +", "era": null, "est_resale_base": 216, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["prata & metal", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
