values ('bruceangeirasleiloeiro-com-br-31203646', 'bruceangeirasleiloeiro-com-br-31203646', '2026-w25-todos', 'PRATA - Vaso elaborado em prata 800 (contraste no fundo) apresentando bojo campaniforme sobre base cônica com fundo estriado e com decoração de botões de flor; parte superior alongada com extremidade pregueada. Peso: 140g. Medindo 16cm.', 1000.0, 'lance r$ 1.000', 'Bruce Angeiras Leilões', 'https://bruceangeirasleiloeiro.com.br/peca.asp?Id=31203646', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62664/31203646.jpg', '2026-06-16 19:00:00', 14.1, 'baixa', 'medio', null, 0, 'queued', '{"uf": "RJ", "house_name": "Bruce Angeiras Leilões", "item_type": "prata_metal", "material": "prata & metal", "size_label": "pequeno", "price_sale": 1800, "price_band": "R$ 1.500 – 2.500", "era": null, "est_resale_base": 216, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["prata & metal", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
