values ('marirodriguesleiloeira-com-br-31130851', 'marirodriguesleiloeira-com-br-31130851', '2026-w25-todos', 'Coador de chá em prata peruana contrastada 925 mls, em formato floral, bordas onduladas e perfurações circulares no bojo central. Cabos laterais vazados e ricamente trabalhados em relevo, com decoração de volutas e flores estilizadas, evocando repertório ornamental barroco/rococó. Trabalho em prata fundida e posteriormente cinzelada, com acabamento manual visível nas superfícies internas. Medidas: 14 cm x 6 cm. Peso - 41 g', 150.0, 'lance r$ 150', 'Marilaine Rodrigues - Leiloeira Pública', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31130851', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31130851.jpg', '2026-06-17 15:00:00', 14.1, 'baixa', 'medio', null, 0, 'queued', '{"uf": "RJ", "house_name": "Marilaine Rodrigues - Leiloeira Pública", "item_type": "prata_metal", "material": "prata & metal", "size_label": "pequeno", "price_sale": 389, "price_band": "até R$ 400", "era": null, "est_resale_base": 216, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["prata & metal", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
