values ('marirodriguesleiloeira-com-br-31130465', 'marirodriguesleiloeira-com-br-31130465', '2026-w25-todos', 'BOLSA FEMININA  Bolsa de mão em prata de lei, com estrutura superior rígida ricamente trabalhada em filigrana e relevos ornamentais, apresentando vazados decorativos e cartelas com motivos florais e arabescados. Corpo confeccionado em malha de prata (chain mail), de caimento flexível, com borda inferior ondulada e acabamento delicado. Acompanha alça articulada em elos de prata, integrada à armação. Fecho tipo clique, funcional. Medidas: 25 cm x 18 cm. Peso: 242 g.', 980.0, 'lance r$ 980', 'Marilaine Rodrigues - Leiloeira Pública', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31130465', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31130465.jpg', '2026-06-17 15:00:00', 14.1, 'baixa', 'medio', null, 1, 'queued', '{"uf": "RJ", "house_name": "Marilaine Rodrigues - Leiloeira Pública", "item_type": "prata_metal", "material": "prata & metal", "size_label": "médio", "price_sale": 1764, "price_band": "R$ 1.500 – 2.500", "era": null, "est_resale_base": 216, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["prata & metal", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
