values ('marirodriguesleiloeira-com-br-31125950', 'marirodriguesleiloeira-com-br-31125950', '2026-w25-todos', 'Caixa retangular confeccionada em prata de lei 900 mls, com tampa levemente abaulada e superfície lisa, de linhas sóbrias e elegantes. Apresenta estrutura robusta, com dobradiça posterior contínua e fecho frontal simples, mantendo estética limpa e funcional. Interior igualmente em prata, evidenciando marcas naturais de uso e pátina compatível com o tempo. Medidas: 5,5 cm (A) x 12 cm (L) x 14,5 cm (comp). Peso 394 g', 2200.0, 'lance r$ 2.200', 'Marilaine Rodrigues - Leiloeira Pública', 'https://marirodriguesleiloeira.com.br/peca.asp?Id=31125950', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/61251/31125950.jpg', '2026-06-17 15:00:00', 14.1, 'baixa', 'medio', null, 1, 'queued', '{"uf": "RJ", "house_name": "Marilaine Rodrigues - Leiloeira Pública", "item_type": "prata_metal", "material": "prata & metal", "size_label": "pequeno", "price_sale": 3960, "price_band": "R$ 2.500 +", "era": null, "est_resale_base": 216, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["prata & metal", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
