values ('mbantiguidades-com-br-31190337', 'mbantiguidades-com-br-31190337', '2026-w25-todos', 'Sofisticado conjunto composto por prato para bolo e 4 pratos sobremesa em porcelana.  Destaca-se pelo contraste  de relevo e pelos grafismos  estilizados em dourado. A transição entre o centro do prato e a borda é esculpida com uma sequencia  de caneletas verticais paralelas criando o efeito de plissado. Med: 32 cm D prato Bolo     14cm D pratos sobremesa.', 80.0, 'lance r$ 80', 'MB Antiguidades', 'https://mbantiguidades.com.br/peca.asp?Id=31190337', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62380/31190337.jpg', '2026-06-15 15:00:00', 13.2, 'baixa', 'medio', null, 0, 'queued', '{"uf": "RJ", "house_name": "MB Antiguidades", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "médio", "price_sale": 227, "price_band": "até R$ 400", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
