values ('vmescritarteleiloes-com-br-31095748', 'vmescritarteleiloes-com-br-31095748', '2026-w25-todos', 'Travessa decorativa de porcelana esmaltada alemã, manufatura bávara "Tirschenreuth", moldada no formato oval com aba em recortes e ornada com barrado e reserva central circular com figurações de sílfides e elfos, emoldurada por arabescos e cercadura com flores estilizadas, em douração a ouro, sobre fundo de cor azul celeste. 28 cm por 39 cm. Alemanha, década de 1940.', 200.0, 'lance r$ 200', 'VM Escritório de Arte', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31095748', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31095748.jpg', '2026-06-18 20:00:00', 13.2, 'baixa', 'medio', null, 1, 'queued', '{"uf": "SP", "house_name": "VM Escritório de Arte", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "médio", "price_sale": 360, "price_band": "até R$ 400", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
