values ('vmescritarteleiloes-com-br-31095120', 'vmescritarteleiloes-com-br-31095120', '2026-w25-todos', 'Prato circular de porcelana vitrificada chinesa, marca "Yinzhang", decorado ao padrão "Famille Rose" (fencai), tendo ao centro reserva com figura feminina em trajes tradicionais , muito comum em representações de cortesãs, damas ou personagens de contos clássicos chineses, circundado por barrado com detalhes florais intercalados por reservas com motes de pássaros e flores. 24,5 cm de diâmetro. China, provavelmente final do reinado Pu Yi (1908 - 1912) da dinastia Qing e início do período republicano.', 300.0, 'lance r$ 300', 'VM Escritório de Arte', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31095120', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31095120.jpg', '2026-06-18 20:00:00', 13.2, 'baixa', 'medio', null, 0, 'queued', '{"uf": "SP", "house_name": "VM Escritório de Arte", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "pequeno", "price_sale": 540, "price_band": "R$ 400 – 800", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
