values ('vmescritarteleiloes-com-br-31091908', 'vmescritarteleiloes-com-br-31091908', '2026-w25-todos', 'Jogo para café de porcelana vitrificada japonesa de Hizen, provavelmente manufatura "Hichozan Shinpo Tsukuru", decorada ao padrão "Kutani" em policromia com "rouge-de-fer" e douração a ouro em cenas de gênero típicas da cultura nipônica, composto de bule com tampa, leiteira, açucareiro com tampa, onze xícaras e treze pires. Total de 27 peças. Japão, período de transição dos séculos XIX e XX. (Apresentando cinco xícaras com "fio de cabelo" e sete pires com imperceptíveis lascas)', 500.0, 'lance r$ 500', 'VM Escritório de Arte', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31091908', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31091908.jpg', '2026-06-18 20:00:00', 13.2, 'baixa', 'medio', null, 0, 'queued', '{"uf": "SP", "house_name": "VM Escritório de Arte", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "pequeno", "price_sale": 900, "price_band": "R$ 800 – 1.500", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
