values ('vmescritarteleiloes-com-br-31091648', 'vmescritarteleiloes-com-br-31091648', '2026-w25-todos', 'Pequeno floreiro de porcelana esmaltada japonesa de Arita moldado no formato bojudo com aba circular lisa e decorado ao padrão "Imari" em reservas de motivos florais estilizados com o "cão de Foo", o guardião dos templos, em "rouge-de-fer". Acompanha base circular de madeira entalhada. 5,5 cm de diâmetro e 9,5 cm de altura, o vaso. Japão, era Meiji (1868 - 1912).', 150.0, 'lance r$ 150', 'VM Escritório de Arte', 'https://vmescritarteleiloes.com.br/peca.asp?Id=31091648', 'https://d1o6h00a1h5k7q.cloudfront.net/imagens/img_m/62422/31091648.jpg', '2026-06-18 20:00:00', 13.2, 'baixa', 'medio', null, 0, 'queued', '{"uf": "SP", "house_name": "VM Escritório de Arte", "item_type": "porcelana_ceramica", "material": "porcelana & cerâmica", "size_label": "pequeno", "price_sale": 270, "price_band": "até R$ 400", "era": null, "est_resale_base": 126, "max_bid_40pct": null, "signal": "CURADA", "approved": false, "tier": null, "entry_reasons": ["porcelana & cerâmica", "peça de catálogo"], "risk_reasons": []}'::jsonb, '2026-06-16T04:19:38Z')
